import React, { useState, useEffect, useCallback, useRef } from 'react';
import { api, apiPost } from '../utils/api';
import { tokens } from '../styles/tokens';
import usePageTitle from '../hooks/usePageTitle';
import s from './PromotionBoardPage.module.css';

/* ═══════════════════════════════════════════════════════════════════════════
   PROMOTION BOARD — Strategy promotion pipeline operator tool
   Fetches /api/promotion/board, shows scoring + blockers + approval flow
   ═══════════════════════════════════════════════════════════════════════════ */

// ── Status config ─────────────────────────────────────────────────────────
const STATUS_CONFIG = {
  PROMOTE: { color: 'var(--color-green, #3FB950)',  bg: 'color-mix(in srgb, var(--color-green, #3FB950) 12%, transparent)', border: 'color-mix(in srgb, var(--color-green, #3FB950) 30%, transparent)' },
  WATCH:   { color: 'var(--color-blue, #58A6FF)',   bg: 'color-mix(in srgb, var(--color-blue, #58A6FF) 12%, transparent)',  border: 'color-mix(in srgb, var(--color-blue, #58A6FF) 30%, transparent)' },
  HOLD:    { color: 'var(--color-textSecondary, #8899AA)', bg: 'color-mix(in srgb, var(--color-textSecondary, #8899AA) 12%, transparent)', border: 'color-mix(in srgb, var(--color-textSecondary, #8899AA) 30%, transparent)' },
  RETEST:  { color: 'var(--color-amber, #D29922)',  bg: 'color-mix(in srgb, var(--color-amber, #D29922) 12%, transparent)', border: 'color-mix(in srgb, var(--color-amber, #D29922) 30%, transparent)' },
  DEMOTE:  { color: 'var(--color-red, #F85149)',    bg: 'color-mix(in srgb, var(--color-red, #F85149) 12%, transparent)',   border: 'color-mix(in srgb, var(--color-red, #F85149) 30%, transparent)' },
};

const FILTERS = ['ALL', 'PROMOTE', 'WATCH', 'HOLD', 'RETEST', 'DEMOTE'];

const POLL_INTERVAL = 30_000;

// ── Helpers ───────────────────────────────────────────────────────────────
function statusCfg(status) {
  return STATUS_CONFIG[status] || STATUS_CONFIG.HOLD;
}

function scoreColor(v) {
  if (v >= 80) return 'var(--color-green, #3FB950)';
  if (v >= 60) return 'var(--color-blue, #58A6FF)';
  if (v >= 40) return 'var(--color-amber, #D29922)';
  return 'var(--color-red, #F85149)';
}

function relativeTime(dateStr) {
  if (!dateStr) return '--';
  const diff = Date.now() - new Date(dateStr).getTime();
  const mins = Math.floor(diff / 60_000);
  if (mins < 1) return 'just now';
  if (mins < 60) return `${mins}m ago`;
  const hrs = Math.floor(mins / 60);
  if (hrs < 24) return `${hrs}h ago`;
  const days = Math.floor(hrs / 24);
  if (days < 30) return `${days}d ago`;
  return `${Math.floor(days / 30)}mo ago`;
}

// ── Refresh icon SVG ──────────────────────────────────────────────────────
function RefreshIcon() {
  return (
    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <polyline points="23 4 23 10 17 10" />
      <path d="M20.49 15a9 9 0 1 1-2.12-9.36L23 10" />
    </svg>
  );
}

// ── Chevron icon ──────────────────────────────────────────────────────────
function ChevronIcon({ open }) {
  return (
    <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"
      style={{ transition: 'transform 0.15s ease', transform: open ? 'rotate(90deg)' : 'rotate(0deg)' }}>
      <polyline points="9 18 15 12 9 6" />
    </svg>
  );
}

/* ═══════════════════════════════════════════════════════════════════════════
   MAIN COMPONENT
   ═══════════════════════════════════════════════════════════════════════════ */
export default function PromotionBoardPage() {
  usePageTitle('Promotion Board');

  const [board, setBoard] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [filter, setFilter] = useState('ALL');
  const [expandedRow, setExpandedRow] = useState(null);
  const [bundleData, setBundleData] = useState({});
  const [bundleLoading, setBundleLoading] = useState({});
  const [approving, setApproving] = useState({});
  const [refreshing, setRefreshing] = useState(false);

  const pollRef = useRef(null);

  // ── Fetch board data ────────────────────────────────────────────────────
  const fetchBoard = useCallback(async (showRefresh) => {
    if (showRefresh) setRefreshing(true);
    try {
      const data = await api('/promotion/board');
      if (data) {
        setBoard(data);
        setError(null);
      }
    } catch (e) {
      setError(e.message || 'Failed to load promotion board');
    } finally {
      setLoading(false);
      if (showRefresh) setRefreshing(false);
    }
  }, []);

  // ── Initial load + polling ──────────────────────────────────────────────
  useEffect(() => {
    fetchBoard(false);
    pollRef.current = setInterval(() => fetchBoard(false), POLL_INTERVAL);
    return () => clearInterval(pollRef.current);
  }, [fetchBoard]);

  // ── Fetch approval bundle on expand ─────────────────────────────────────
  const handleExpand = useCallback(async (name) => {
    if (expandedRow === name) {
      setExpandedRow(null);
      return;
    }
    setExpandedRow(name);

    if (!bundleData[name] && !bundleLoading[name]) {
      setBundleLoading(prev => ({ ...prev, [name]: true }));
      try {
        const data = await api(`/promotion/approval-bundle/${encodeURIComponent(name)}`);
        if (data) {
          setBundleData(prev => ({ ...prev, [name]: data }));
        }
      } catch {
        // silently fail — detail section will show without bundle
      } finally {
        setBundleLoading(prev => ({ ...prev, [name]: false }));
      }
    }
  }, [expandedRow, bundleData, bundleLoading]);

  // ── Approve strategy ────────────────────────────────────────────────────
  const handleApprove = useCallback(async (name, e) => {
    if (e) e.stopPropagation();
    setApproving(prev => ({ ...prev, [name]: true }));
    try {
      const result = await apiPost(`/promotion/approve/${encodeURIComponent(name)}`, {});
      if (result) {
        // Refresh board after approval
        await fetchBoard(false);
      }
    } catch {
      // toast will show from api.js
    } finally {
      setApproving(prev => ({ ...prev, [name]: false }));
    }
  }, [fetchBoard]);

  // ── Derive data ─────────────────────────────────────────────────────────
  const strategies = board?.strategies || board?.board || [];

  const sorted = [...strategies].sort((a, b) =>
    (b.promotion_score ?? b.score ?? 0) - (a.promotion_score ?? a.score ?? 0)
  );

  const filtered = filter === 'ALL'
    ? sorted
    : sorted.filter(s => (s.status || '').toUpperCase() === filter);

  const counts = {};
  for (const f of FILTERS) counts[f] = 0;
  for (const strat of strategies) {
    const st = (strat.status || '').toUpperCase();
    if (counts[st] !== undefined) counts[st]++;
    counts.ALL++;
  }

  // Strategies ready for approval: PROMOTE status + no blockers
  const readyForApproval = sorted.filter(s =>
    (s.status || '').toUpperCase() === 'PROMOTE' &&
    (!s.blockers || s.blockers.length === 0)
  );

  // ── Loading state ───────────────────────────────────────────────────────
  if (loading && !board) {
    return <div className={s.page}><div className={s.loadingState}>Loading promotion board...</div></div>;
  }

  return (
    <div className={s.page}>
      {/* ── Header ────────────────────────────────────────────────────── */}
      <div className={s.header}>
        <div className={s.headerLeft}>
          <h1 className={s.title}>Promotion Board</h1>
          <button
            className={`${s.refreshBtn} ${refreshing ? s.refreshBtnSpinning : ''}`}
            onClick={() => fetchBoard(true)}
            disabled={refreshing}
          >
            <RefreshIcon /> {refreshing ? 'Refreshing...' : 'Refresh'}
          </button>
        </div>
        <div className={s.filterRow}>
          {FILTERS.map(f => (
            <button
              key={f}
              className={filter === f ? s.filterPillActive : s.filterPill}
              onClick={() => setFilter(f)}
            >
              {f} {counts[f] > 0 ? `(${counts[f]})` : ''}
            </button>
          ))}
        </div>
      </div>

      {/* ── Error ─────────────────────────────────────────────────────── */}
      {error && <div className={s.errorBanner}>{error}</div>}

      {/* ── Approval banner ───────────────────────────────────────────── */}
      {readyForApproval.length > 0 && (
        <div className={s.approvalBanner}>
          <span className={s.approvalTitle}>
            {readyForApproval.length} read{readyForApproval.length === 1 ? 'y' : 'y'} for approval
          </span>
          <div className={s.approvalList}>
            {readyForApproval.map(strat => (
              <div key={strat.strategy || strat.name} className={s.approvalChip}>
                <span className={s.approvalChipName}>{strat.strategy || strat.name}</span>
                <button
                  className={s.approveBtn}
                  onClick={(e) => handleApprove(strat.strategy || strat.name, e)}
                  disabled={approving[strat.strategy || strat.name]}
                >
                  {approving[strat.strategy || strat.name] ? 'Approving...' : 'Approve'}
                </button>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* ── Summary cards ─────────────────────────────────────────────── */}
      <div className={s.summaryRow}>
        {['PROMOTE', 'WATCH', 'HOLD', 'RETEST', 'DEMOTE'].map(st => (
          <div key={st} className={s.summaryCard}>
            <span className={s.summaryValue} style={{ color: statusCfg(st).color }}>
              {counts[st] || 0}
            </span>
            <span className={s.summaryLabel}>{st}</span>
          </div>
        ))}
      </div>

      {/* ── Main table ────────────────────────────────────────────────── */}
      {filtered.length === 0 ? (
        <div className={s.emptyState}>
          {filter === 'ALL'
            ? 'No strategies in the promotion pipeline yet.'
            : `No strategies with status "${filter}".`}
        </div>
      ) : (
        <div className={s.tableWrap}>
          <table className={s.table}>
            <thead>
              <tr>
                <th style={{ width: 40 }}>#</th>
                <th>Strategy</th>
                <th>Score</th>
                <th>Confidence</th>
                <th>Status</th>
                <th>Blockers</th>
                <th>Next Action</th>
                <th>Last Tested</th>
              </tr>
            </thead>
            <tbody>
              {filtered.map((strat, idx) => {
                const name = strat.strategy || strat.name || `strategy-${idx}`;
                const promoScore = strat.promotion_score ?? strat.score ?? 0;
                const confScore = strat.confidence_score ?? strat.confidence ?? 0;
                const status = (strat.status || 'HOLD').toUpperCase();
                const blockers = strat.blockers || [];
                const nextAction = strat.next_action || strat.recommendation || '--';
                const lastTested = strat.last_tested || strat.last_backtest || null;
                const isExpanded = expandedRow === name;
                const cfg = statusCfg(status);

                return (
                  <React.Fragment key={name}>
                    {/* ── Main row ─────────────────────────────── */}
                    <tr
                      className={isExpanded ? s.tableRowExpanded : s.tableRow}
                      onClick={() => handleExpand(name)}
                    >
                      <td className={s.rank}>
                        <ChevronIcon open={isExpanded} /> {idx + 1}
                      </td>
                      <td className={s.stratName}>{name}</td>
                      <td>
                        <div className={s.scoreCell}>
                          <div className={s.scoreBarTrack}>
                            <div className={s.scoreBarFill} style={{
                              width: `${Math.min(100, Math.max(0, promoScore))}%`,
                              background: scoreColor(promoScore),
                            }} />
                          </div>
                          <span className={s.scoreValue} style={{ color: scoreColor(promoScore) }}>
                            {Math.round(promoScore)}
                          </span>
                        </div>
                      </td>
                      <td>
                        <div className={s.confScoreCell}>
                          <div className={s.confBarTrack}>
                            <div className={s.confBarFill} style={{
                              width: `${Math.min(100, Math.max(0, confScore))}%`,
                              background: scoreColor(confScore),
                            }} />
                          </div>
                          <span className={s.scoreValue} style={{
                            color: scoreColor(confScore),
                            fontSize: 11,
                          }}>
                            {Math.round(confScore)}
                          </span>
                        </div>
                      </td>
                      <td>
                        <span className={s.statusBadge} style={{
                          background: cfg.bg,
                          border: `1px solid ${cfg.border}`,
                          color: cfg.color,
                        }}>
                          {status}
                        </span>
                      </td>
                      <td>
                        <div className={s.blockersCell}>
                          {blockers.length === 0 ? (
                            <span style={{ color: 'var(--color-textSecondary, #8899AA)', fontSize: 12 }}>--</span>
                          ) : (
                            blockers.map((b, i) => (
                              <span key={i} className={s.blockerPill}>{b}</span>
                            ))
                          )}
                        </div>
                      </td>
                      <td className={s.nextAction} title={nextAction}>{nextAction}</td>
                      <td className={s.lastTested}>{relativeTime(lastTested)}</td>
                    </tr>

                    {/* ── Expanded detail row ──────────────────── */}
                    {isExpanded && (
                      <tr className={s.detailRow}>
                        <td colSpan={8}>
                          <ExpandedDetail
                            strat={strat}
                            name={name}
                            bundle={bundleData[name]}
                            bundleLoading={bundleLoading[name]}
                            approving={approving[name]}
                            onApprove={() => handleApprove(name)}
                            onLoadBundle={() => {
                              if (!bundleData[name] && !bundleLoading[name]) {
                                setBundleLoading(prev => ({ ...prev, [name]: true }));
                                api(`/promotion/approval-bundle/${encodeURIComponent(name)}`)
                                  .then(data => {
                                    if (data) setBundleData(prev => ({ ...prev, [name]: data }));
                                  })
                                  .finally(() => setBundleLoading(prev => ({ ...prev, [name]: false })));
                              }
                            }}
                            status={status}
                          />
                        </td>
                      </tr>
                    )}
                  </React.Fragment>
                );
              })}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════════════
   EXPANDED DETAIL — scoring breakdown + approval bundle
   ═══════════════════════════════════════════════════════════════════════════ */
function ExpandedDetail({ strat, name, bundle, bundleLoading, approving, onApprove, onLoadBundle, status }) {
  // Extract scoring components from the strategy data
  const scoring = strat.scoring || strat.score_breakdown || strat.components || {};
  const scoringEntries = Object.entries(scoring);

  const blockers = strat.blockers || [];
  const canApprove = status === 'PROMOTE' && blockers.length === 0;

  return (
    <div className={s.detailContent}>
      {/* ── Scoring breakdown ──────────────────────────────────────── */}
      {scoringEntries.length > 0 && (
        <div className={s.detailSection}>
          <h4 className={s.detailSectionTitle}>Scoring Breakdown</h4>
          <div className={s.breakdownGrid}>
            {scoringEntries.map(([key, val]) => {
              const numVal = typeof val === 'number' ? val : (val?.score ?? val?.value ?? 0);
              return (
                <div key={key} className={s.breakdownItem}>
                  <span className={s.breakdownLabel}>{formatLabel(key)}</span>
                  <span className={s.breakdownValue} style={{ color: scoreColor(numVal) }}>
                    {typeof numVal === 'number' ? numVal.toFixed(1) : numVal}
                  </span>
                  <div className={s.breakdownBar}>
                    <div className={s.breakdownBarFill} style={{
                      width: `${Math.min(100, Math.max(0, numVal))}%`,
                      background: scoreColor(numVal),
                    }} />
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {/* ── Strategy metadata ──────────────────────────────────────── */}
      {(strat.win_rate != null || strat.total_trades != null || strat.sharpe != null || strat.max_drawdown != null) && (
        <div className={s.detailSection}>
          <h4 className={s.detailSectionTitle}>Performance Metrics</h4>
          <div className={s.breakdownGrid}>
            {strat.win_rate != null && (
              <div className={s.breakdownItem}>
                <span className={s.breakdownLabel}>Win Rate</span>
                <span className={s.breakdownValue} style={{ color: strat.win_rate >= 50 ? 'var(--color-green, #3FB950)' : 'var(--color-red, #F85149)' }}>
                  {typeof strat.win_rate === 'number' ? `${strat.win_rate.toFixed(1)}%` : strat.win_rate}
                </span>
              </div>
            )}
            {strat.total_trades != null && (
              <div className={s.breakdownItem}>
                <span className={s.breakdownLabel}>Total Trades</span>
                <span className={s.breakdownValue}>{strat.total_trades}</span>
              </div>
            )}
            {strat.sharpe != null && (
              <div className={s.breakdownItem}>
                <span className={s.breakdownLabel}>Sharpe Ratio</span>
                <span className={s.breakdownValue} style={{ color: strat.sharpe >= 1 ? 'var(--color-green, #3FB950)' : 'var(--color-amber, #D29922)' }}>
                  {typeof strat.sharpe === 'number' ? strat.sharpe.toFixed(2) : strat.sharpe}
                </span>
              </div>
            )}
            {strat.max_drawdown != null && (
              <div className={s.breakdownItem}>
                <span className={s.breakdownLabel}>Max Drawdown</span>
                <span className={s.breakdownValue} style={{ color: 'var(--color-red, #F85149)' }}>
                  {typeof strat.max_drawdown === 'number' ? `${strat.max_drawdown.toFixed(1)}%` : strat.max_drawdown}
                </span>
              </div>
            )}
            {strat.profit_factor != null && (
              <div className={s.breakdownItem}>
                <span className={s.breakdownLabel}>Profit Factor</span>
                <span className={s.breakdownValue} style={{ color: strat.profit_factor >= 1.5 ? 'var(--color-green, #3FB950)' : 'var(--color-amber, #D29922)' }}>
                  {typeof strat.profit_factor === 'number' ? strat.profit_factor.toFixed(2) : strat.profit_factor}
                </span>
              </div>
            )}
            {strat.expectancy != null && (
              <div className={s.breakdownItem}>
                <span className={s.breakdownLabel}>Expectancy</span>
                <span className={s.breakdownValue} style={{ color: strat.expectancy >= 0 ? 'var(--color-green, #3FB950)' : 'var(--color-red, #F85149)' }}>
                  {typeof strat.expectancy === 'number' ? `$${strat.expectancy.toFixed(2)}` : strat.expectancy}
                </span>
              </div>
            )}
          </div>
        </div>
      )}

      {/* ── Approval bundle preview ────────────────────────────────── */}
      {bundle && (
        <div className={s.bundlePreview}>
          <h4 className={s.bundlePreviewTitle}>Approval Bundle</h4>
          <div className={s.bundleKV}>
            {Object.entries(bundle).map(([k, v]) => (
              <React.Fragment key={k}>
                <span className={s.bundleKey}>{formatLabel(k)}</span>
                <span className={s.bundleVal}>
                  {typeof v === 'object' ? JSON.stringify(v) : String(v)}
                </span>
              </React.Fragment>
            ))}
          </div>
        </div>
      )}

      {/* ── Actions ────────────────────────────────────────────────── */}
      <div className={s.detailActions}>
        <button
          className={s.bundleBtn}
          onClick={onLoadBundle}
          disabled={bundleLoading || !!bundle}
        >
          {bundleLoading ? 'Loading bundle...' : bundle ? 'Bundle loaded' : 'Load Approval Bundle'}
        </button>
        {canApprove && (
          <button
            className={s.approveDetailBtn}
            onClick={onApprove}
            disabled={approving}
          >
            {approving ? 'Approving...' : 'Approve for Promotion'}
          </button>
        )}
      </div>
    </div>
  );
}

/* ── Format snake_case / camelCase labels to Title Case ─────────────────── */
function formatLabel(key) {
  return key
    .replace(/_/g, ' ')
    .replace(/([a-z])([A-Z])/g, '$1 $2')
    .replace(/\b\w/g, c => c.toUpperCase());
}
